13	
14	  Breadcrumb component
15	
16	  Draws the breadcrumb
17	
18	--%><%@include file="/libs/foundation/global.jsp"%><%
19	%>
20	   
21	<div id="breadcrumbs" class="max-width-1200px center-aligned">
22	    <div class="row hide-medium-small">
23	    <div class="column">
24	<%
25	    // get starting point of trail
26	    long absParent = currentStyle.get("absParent", 2L);
27		long level = absParent;
28	    long endLevel = currentStyle.get("relParent", 1L);
29	    String delimStr = ">";
30	    String trailStr = currentStyle.get("trail", "");
31	    int currentLevel = currentPage.getDepth();
32	    String delim = "";
33		
34		if(endLevel==0){
35			endLevel=currentLevel;
36		}
37	
38	    while (level <= endLevel) {
39	        Page trail = currentPage.getAbsoluteParent((int) level);
40	        
41	        if (trail == null) {
42	            break;
43	        }
44	        
45	        String title = trail.getTitle();
46	        if (title == null || title.equals("")) {
47	            title = trail.getNavigationTitle();
48	        }
49	        if (title == null || title.equals("")) {
50	            title = trail.getTitle();
51	        }
52	        if (title == null || title.equals("")) {
53	            title = trail.getName();
54	        }
55	        
56	        
57	         if(!trail.isHideInNav()){    
58	        	 if(level == currentLevel - 1){
59	        		 %>
60	 		        <span class="delimiter"><%= xssAPI.filterHTML(delim) %></span>
61	 		        <span aria-label="breadcrumbs" aria-current="location" tabindex="0" class="emc-color-3 current-page-breadcrumb">
62	 		          <%= xssAPI.encodeForHTML(title) %>
63	 		        </span>
64	 		        <%
65	        	 }
66	        	 else if(level > absParent){
67			        %>
68			        <span class="delimiter"><%= xssAPI.filterHTML(delim) %></span>
69			        <span>
70			        <a aria-label="breadcrumbs" title="<%= xssAPI.encodeForHTML(title) %>" href="<%= xssAPI.getValidHref(trail.getPath()+".html") %>" class="handheld-hide"><%= xssAPI.encodeForHTML(title) %></a>
71			        </span>
72			        <%
73		         }
74	        	 else{             	
75	       	        %>
76	       	        <span><%= xssAPI.filterHTML(delim) %></span>
77	       	        <span>
78	       	        <a aria-label="breadcrumbs" title="<%= xssAPI.encodeForHTML(title) %>" href="<%= xssAPI.getValidHref(trail.getPath()+".html") %>" class="handheld-hide" id="home-breadcrumb"><%= xssAPI.encodeForHTML(title) %></a>
79	                </span>
80	            <%
81	             }        	 
82	        }
83	        
84	        delim = delimStr;
85	        level++;
86	
87	     }
88	
89		if (trailStr.length() > 0) {
90	        %><%= xssAPI.filterHTML(trailStr) %><%
91	    }
92	
93	%>
94	        </div>
95	    </div>
96	</div>
